#!/usr/bin/env node
'use strict';

const fs = require('fs');
const path = require('path');
const os = require('os');

// Embedded dev.md content — generated by build.js, do not edit directly.
// {{DEV_MD}}

// ---------------------------------------------------------------------------
// Argument parsing
// ---------------------------------------------------------------------------

function printHelp() {
  console.log(`k-mcp-devkit installer

Usage:
  npx github:kusimari/k-mcp-devkit <agent> [--global]
  node build/install.js <agent> [--global]

Agents:
  claude-code   Claude Code  (.claude/commands/ or ~/.claude/commands/)
  gemini        Gemini CLI   (GEMINI.md or ~/.gemini/GEMINI.md)
  kiro          Amazon Kiro  (.kiro/steering/)

Flags:
  --global      Install at user scope rather than project scope
                (Claude Code and Gemini only; Kiro is project-only)

Examples:
  npx github:kusimari/k-mcp-devkit claude-code
  npx github:kusimari/k-mcp-devkit gemini --global
  node build/install.js kiro
`);
}

function parseArgs(argv) {
  const opts = { agent: null, global: false };
  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i];
    if (arg === '--agent') {
      if (!argv[i + 1]) { die('--agent requires a value'); }
      opts.agent = argv[++i];
    } else if (arg === '--global') {
      opts.global = true;
    } else if (arg === '--help' || arg === '-h') {
      printHelp();
      process.exit(0);
    } else if (!arg.startsWith('-')) {
      opts.agent = arg;
    } else {
      die(`Unknown option: ${arg}`);
    }
  }
  return opts;
}

function die(msg) {
  console.error(`Error: ${msg}`);
  console.error('Run with --help for usage.');
  process.exit(1);
}

// ---------------------------------------------------------------------------
// File helpers
// ---------------------------------------------------------------------------

function writeFile(dest, content) {
  fs.mkdirSync(path.dirname(dest), { recursive: true });
  fs.writeFileSync(dest, content);
  console.log(`  installed: ${dest}`);
}

function appendSection(targetFile, heading, content) {
  const existing = fs.existsSync(targetFile) ? fs.readFileSync(targetFile, 'utf8') : '';
  if (existing.includes(heading)) {
    console.log(`  skipped (already present): ${heading} in ${path.basename(targetFile)}`);
    return false;
  }
  fs.mkdirSync(path.dirname(targetFile), { recursive: true });
  fs.appendFileSync(targetFile, `\n${heading}\n\n${content}`);
  console.log(`  appended: ${heading} → ${path.basename(targetFile)}`);
  return true;
}

// ---------------------------------------------------------------------------
// Agent installers
// ---------------------------------------------------------------------------

function installClaudeCode(opts) {
  const scope = opts.global ? 'global' : 'project';
  const targetDir = opts.global
    ? path.join(os.homedir(), '.claude', 'commands')
    : path.join(process.cwd(), '.claude', 'commands');
  writeFile(path.join(targetDir, 'dev.md'), DEV_MD);
  console.log(`\nClaude Code: dev command installed (scope: ${scope})`);
  console.log('Invoke with /dev [feature]');
}

function installGemini(opts) {
  const scope = opts.global ? 'global' : 'project';
  const targetFile = opts.global
    ? path.join(os.homedir(), '.gemini', 'GEMINI.md')
    : path.join(process.cwd(), 'GEMINI.md');
  const heading = '## k-mcp-devkit: dev';
  appendSection(targetFile, heading, DEV_MD);
  console.log(`\nGemini CLI: dev section in ${targetFile} (scope: ${scope})`);
  console.log('Activate by asking the model to apply the k-mcp-devkit dev section.');
}

function installKiro(opts) {
  if (opts.global) {
    console.warn('Warning: Kiro does not support global steering files. Installing at project scope.');
  }
  const targetDir = path.join(process.cwd(), '.kiro', 'steering');
  writeFile(path.join(targetDir, 'dev.md'), DEV_MD);
  console.log(`\nKiro: dev steering file installed → ${path.join(targetDir, 'dev.md')}`);
  console.log('Active in every Kiro session for this project.');
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

const opts = parseArgs(process.argv.slice(2));

if (!opts.agent) {
  printHelp();
  process.exit(1);
}

const scopeLabel = opts.global ? ' (global)' : ' (project)';
console.log(`Installing k-mcp-devkit dev command for: ${opts.agent}${scopeLabel}`);
console.log('');

switch (opts.agent) {
  case 'claude-code': installClaudeCode(opts); break;
  case 'gemini':      installGemini(opts);      break;
  case 'kiro':        installKiro(opts);        break;
  default:
    die(`unknown agent '${opts.agent}'.\nAvailable: claude-code, gemini, kiro`);
}
